import { useEffect, useState } from 'react'
import ListGroup from 'react-bootstrap/ListGroup'
import ListGroupItem from 'react-bootstrap/ListGroup'
// import { Link } from 'react-router-dom'
import StarWarsAPI from '../services/StarWarsAPI'
import CardGroup from 'react-bootstrap/CardGroup'
import Card from 'react-bootstrap/Card'
import CardBody from 'react-bootstrap/Card'
import Button from 'react-bootstrap/Button'


const Films = () => {
	const [films, setFilms] = useState([])

	const getFilms = async () => {

		const data = await StarWarsAPI.getFilms()

        setFilms(data);
	}


	useEffect(() => {
		getFilms()
	}, [])

	return (
		<>
			<h1>Films</h1>

			{films.length > 0 && (
				<CardGroup className="filmslist">
					{films.map(film =>
						<Card>
                            <Card.Img variant="top" src=""/>
                            <CardBody>
                            <Card.Title>{film.title}</Card.Title>
                            <ListGroup className="film-info">
                            <ListGroupItem>Episode {film.episode_id}</ListGroupItem>
                            <ListGroupItem>Released {film.release_date}</ListGroupItem>
                            <ListGroupItem>{film.characters.length} characters</ListGroupItem>
                            </ListGroup>
                            <Button variant="primary" href="{}">Read more</Button>
                            </CardBody>

						</Card>
					)}
				</CardGroup>
			)} 

			{films.length === 0 && (
				<p className="status">No films 🥳!</p>
			)}
		</>
	)
}

export default Films;
